import prisma from "@/lib/prisma";
import { revalidatePath } from "next/cache";
import { redirect } from "next/navigation";
import { PlusIcon, TrashIcon, DocumentTextIcon } from "@heroicons/react/24/outline";

export const dynamic = "force-dynamic";

const PAGES = [
    { slug: "hakkimizda", name: "Hakkımızda" },
    { slug: "iletisim", name: "İletişim" },
    { slug: "orgun-egitim", name: "Örgün Eğitim" },
    { slug: "home", name: "Ana Sayfa" },
];

async function upsertContent(formData: FormData) {
    "use server";
    const pageSlug = formData.get("pageSlug") as string;
    const sectionKey = formData.get("sectionKey") as string;
    const title = formData.get("title") as string || null;
    const content = formData.get("content") as string || null;

    await prisma.pageContent.upsert({
        where: { pageSlug_sectionKey: { pageSlug, sectionKey } },
        update: { title, content },
        create: { pageSlug, sectionKey, title, content },
    });
    revalidatePath("/admin/sayfalar");
    redirect("/admin/sayfalar");
}

async function deleteContent(formData: FormData) {
    "use server";
    await prisma.pageContent.delete({ where: { id: formData.get("id") as string } });
    revalidatePath("/admin/sayfalar");
}

export default async function AdminSayfalarPage() {
    const contents = await prisma.pageContent.findMany({ orderBy: [{ pageSlug: "asc" }, { sectionKey: "asc" }] });

    // Sayfalara göre grupla
    const grouped = PAGES.map((p) => ({
        ...p,
        items: contents.filter((c) => c.pageSlug === p.slug),
    }));

    return (
        <div className="space-y-6">
            <div>
                <h1 className="text-2xl font-bold text-gray-900">Sayfa İçerikleri</h1>
                <p className="text-gray-500 text-sm">Statik sayfa metinlerini düzenleyin.</p>
            </div>

            {/* Yeni İçerik Ekle */}
            <div className="bg-white rounded-xl border border-gray-200 p-6">
                <h2 className="text-base font-semibold text-gray-900 mb-4">İçerik Ekle / Güncelle</h2>
                <form action={upsertContent} className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <select name="pageSlug" required className="px-4 py-2.5 border border-gray-200 rounded-lg text-sm outline-none bg-white">
                        {PAGES.map((p) => <option key={p.slug} value={p.slug}>{p.name}</option>)}
                    </select>
                    <input name="sectionKey" placeholder="Bölüm Anahtarı (örn: hero-title, mission-text) *" required className="px-4 py-2.5 border border-gray-200 rounded-lg text-sm outline-none" />
                    <input name="title" placeholder="Başlık" className="px-4 py-2.5 border border-gray-200 rounded-lg text-sm outline-none md:col-span-2" />
                    <textarea name="content" placeholder="İçerik Metni" rows={4} className="px-4 py-2.5 border border-gray-200 rounded-lg text-sm outline-none resize-none md:col-span-2" />
                    <div className="md:col-span-2">
                        <button type="submit" className="inline-flex items-center gap-2 px-5 py-2.5 bg-primary text-white rounded-lg text-sm font-medium hover:bg-primary/90">
                            <PlusIcon className="w-4 h-4" /> Kaydet
                        </button>
                    </div>
                </form>
            </div>

            {/* Mevcut İçerikler */}
            {grouped.map((page) => (
                <div key={page.slug} className="bg-white rounded-xl border border-gray-200 overflow-hidden">
                    <div className="px-5 py-3 bg-gray-50 border-b border-gray-100">
                        <h3 className="text-sm font-bold text-gray-700">{page.name}</h3>
                    </div>
                    {page.items.length === 0 ? (
                        <div className="p-6 text-center text-gray-400 text-sm">Bu sayfa için henüz içerik eklenmemiş.</div>
                    ) : (
                        <div className="divide-y divide-gray-50">
                            {page.items.map((item) => (
                                <div key={item.id} className="px-5 py-3 flex items-start justify-between gap-4">
                                    <div className="flex-1 min-w-0">
                                        <span className="text-xs font-mono bg-gray-100 px-1.5 py-0.5 rounded text-gray-500">{item.sectionKey}</span>
                                        {item.title && <p className="font-medium text-gray-900 text-sm mt-1">{item.title}</p>}
                                        {item.content && <p className="text-xs text-gray-500 mt-1 line-clamp-2">{item.content}</p>}
                                    </div>
                                    <form action={deleteContent}>
                                        <input type="hidden" name="id" value={item.id} />
                                        <button type="submit" className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg">
                                            <TrashIcon className="w-4 h-4" />
                                        </button>
                                    </form>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            ))}
        </div>
    );
}
